(function () {
  window.Toastify = function (options) {
    options = options || {};
    return {
      showToast: function () {
        var toast = document.createElement('div');
        var gravity = options.gravity === 'top' ? 'top' : 'bottom';
        var position = options.position === 'left' ? 'left' : 'right';
        toast.className = 'toastify toastify-' + gravity + ' toastify-' + position
          + (options.className ? ' ' + options.className : '');
        toast.textContent = options.text || '';
        document.body.appendChild(toast);
        requestAnimationFrame(function () {
          toast.classList.add('on');
        });
        setTimeout(function () {
          toast.classList.remove('on');
          toast.classList.add('is-leaving');
          setTimeout(function () {
            if (toast.parentNode) toast.parentNode.removeChild(toast);
          }, 180);
        }, options.duration || 2500);
        return toast;
      }
    };
  };
})();
